pair A,B,C,D,EE,F,G,H,P;

A = rotate(-67.5)*(1,0);
B = rotate(45)*A;
C=rotate(45)*B;
D = rotate(45)*C;
EE = rotate(45)*D;
F = rotate(45)*EE;
G = rotate(45)*F;
H = rotate(45)*G;

P = A + (rotate(-90)*(D-A));
draw (A--B--C--D--EE--F--G--H--A--P--C,linewidth(1));
label("$A$",A,S);
label("$B$",B,SE);
label("$C$",C,NE);
label("$D$",D,N);
label("$E$",EE,N);
label("$F$",F,W);
label("$G$",G,W);
label("$H$",H,S);
label("$P$",P,S);
[/asy]

